$env:PINCHTAB_URL = "http://localhost:9868"; pinchtab eval "
(function() {
  // Find the accepted answer
  var acceptedAnswer = document.querySelector('.answer.accepted-answer') || document.querySelector('[data-is-accepted=\"true\"]') || document.querySelector('.js-accepted-answer');
  if (!acceptedAnswer) {
    // Try other selectors
    var answers = document.querySelectorAll('.answer');
    for (var i = 0; i < answers.length; i++) {
      if (answers[i].classList.contains('accepted-answer') || answers[i].querySelector('.js-accepted-answer-symbol') || answers[i].querySelector('.accepted-mark')) {
        acceptedAnswer = answers[i];
        break;
      }
    }
  }

  var result = {
    acceptedAnswerFound: !!acceptedAnswer,
    acceptedAnswerClasses: acceptedAnswer ? acceptedAnswer.className : 'NOT FOUND'
  };

  if (acceptedAnswer) {
    // Get vote count
    var voteEl = acceptedAnswer.querySelector('.js-vote-count') || acceptedAnswer.querySelector('[itemprop=\"upvoteCount\"]') || acceptedAnswer.querySelector('.vote-count-post');
    result.voteCount = voteEl ? voteEl.textContent.trim() : 'not found';
    result.voteElClass = voteEl ? voteEl.className : 'not found';

    // Get author
    var authorEl = acceptedAnswer.querySelector('.user-details a') || acceptedAnswer.querySelector('.answerer a') || acceptedAnswer.querySelector('[itemprop=\"author\"] a');
    result.author = authorEl ? authorEl.textContent.trim() : 'not found';

    // Count code blocks
    var codeBlocks = acceptedAnswer.querySelectorAll('pre code, pre');
    result.codeBlockCount = codeBlocks.length;
    result.preCount = acceptedAnswer.querySelectorAll('pre').length;
    result.codeCount = acceptedAnswer.querySelectorAll('code').length;
    result.preCodeCount = acceptedAnswer.querySelectorAll('pre code').length;
  }

  // Total answers count
  var answersHeader = document.querySelector('#answers-header h2') || document.querySelector('.answers-subheader h2');
  result.answersHeader = answersHeader ? answersHeader.textContent.trim() : 'not found';

  // Also check alternative
  var answersCount = document.querySelector('[data-answercount]');
  result.dataAnswerCount = answersCount ? answersCount.getAttribute('data-answercount') : 'not found';

  return JSON.stringify(result, null, 2);
})()"

curl -s "http://localhost:9868/tabs/tab_74fe0c56/eval" -X POST -H "Content-Type: application/json" -d '{
  "expression": "(function() { var acceptedAnswer = document.querySelector(\".answer.accepted-answer\"); if (!acceptedAnswer) { var answers = document.querySelectorAll(\".answer\"); for (var i = 0; i < answers.length; i++) { if (answers[i].classList.contains(\"accepted-answer\")) { acceptedAnswer = answers[i]; break; } } } var result = {}; result.found = !!acceptedAnswer; if (acceptedAnswer) { var voteEl = acceptedAnswer.querySelector(\".js-vote-count\"); result.votes = voteEl ? voteEl.textContent.trim() : \"not found\"; var authorEl = acceptedAnswer.querySelector(\".user-details a\"); result.author = authorEl ? authorEl.textContent.trim() : \"not found\"; result.preCount = acceptedAnswer.querySelectorAll(\"pre\").length; result.codeCount = acceptedAnswer.querySelectorAll(\"code\").length; result.preCodeCount = acceptedAnswer.querySelectorAll(\"pre code\").length; result.acceptedId = acceptedAnswer.getAttribute(\"data-answerid\"); } var ah = document.querySelector(\"#answers-header h2\"); result.answersHeader = ah ? ah.textContent.trim() : \"not found\"; var ac = document.querySelector(\"[data-answercount]\"); result.dataAnswerCount = ac ? ac.getAttribute(\"data-answercount\") : \"not found\"; return JSON.stringify(result); })()"
}'

