}'

curl -s -X POST "http://localhost:9868/evaluate" -H "Content-Type: application/json" -d '{
  "tabId": "tab_74fe0c56",
  "expression": "(function() { var acceptedAnswer = document.querySelector(\".answer.accepted-answer\"); var pres = acceptedAnswer.querySelectorAll(\"pre\"); var result = { preCount: pres.length, preDetails: [] }; pres.forEach(function(pre, i) { var hasCode = !!pre.querySelector(\"code\"); var snippet = pre.textContent.substring(0,60).replace(/\\n/g,\" \"); result.preDetails.push({index: i, hasCode: hasCode, snippet: snippet}); }); return JSON.stringify(result); })()"
}'

curl -s -X POST "http://localhost:9868/evaluate" -H "Content-Type: application/json" -d '{
  "tabId": "tab_74fe0c56",
  "expression": "(function() { var a = document.querySelector(\".answer.accepted-answer\"); var pres = a.querySelectorAll(\"pre\"); var result = { preCount: pres.length, withCode: 0, withoutCode: 0 }; pres.forEach(function(p) { if (p.querySelector(\"code\")) result.withCode++; else result.withoutCode++; }); return JSON.stringify(result); })()"
}'

